/* ============================================================
   Seiteninhalte (Body-HTML pro Route). Nutzt templates.js.
   ============================================================ */

var SPEC_YIELD = { nord:950, mitte:1020, sued:1100 };

function calcStatic(){
  var CP = prod('one-plus'); var region='sued'; var strom=35;
  var yieldKwh = Math.round(CP.kwp * SPEC_YIELD[region]);
  var savings = yieldKwh * strom / 100;
  return { yieldKwh:yieldKwh, savings:savings, amort:CP.price/savings, ers25:savings*25, CP:CP };
}
function calcNote(CP){ return 'Berechnung auf Basis des ' + CP.name + ' mit ' + CP.wp + ' Wp-Solarmodul, optimal geneigt um 25°. Richtwerte bei vollständiger Eigennutzung des erzeugten Stroms.'; }
function calcProductsHtml(activeId){
  return PRODUCTS.map(function(p){
    var active = activeId === p.id;
    var style = 'flex:1; cursor:pointer; text-align:center; padding:13px 8px; border-radius:14px; transition:all .15s; border:1.5px solid ' + (active?'#111113':'#d2d2d7') + '; background:' + (active?'#111113':'#ffffff') + '; color:' + (active?'#ffffff':'#1d1d1f') + ';';
    var subStyle = 'font-size:12px; margin-top:2px; color:' + (active?'rgba(255,255,255,0.7)':'#86868b') + ';';
    return '<button type="button" data-calc-select="'+p.id+'" style="'+style+'"><div style="font-weight:700; font-size:15px;">'+p.shortLabel+'</div><div style="'+subStyle+'">'+p.wp+' Wp</div></button>';
  }).join('');
}

