/* ---------------- ÜBER UNS ---------------- */
function pageAbout(){
  return '<div style="background:#ffffff;">'
  + '<section style="background:#0a0a0c; padding:120px 32px;"><div style="max-width:860px; margin:0 auto; text-align:center;"><div style="color:#86868b; font-weight:600; font-size:13px; letter-spacing:0.12em; text-transform:uppercase; margin-bottom:16px;">Über uns</div><h1 style="margin:0 0 22px; font-size:50px; line-height:1.14; font-weight:700; letter-spacing:-0.02em; color:#ffffff;">Wir bringen die Energiewende auf deine Terrasse.</h1><p style="margin:0 auto; max-width:560px; font-size:17px; line-height:1.65; color:#86868b;">Sustable steht für Solarmöbel, die Design und nachhaltige Energie verbinden – durchdacht entwickelt, regional und fair gefertigt in Deutschland.</p></div></section>'
  + '<section style="padding:110px 32px; background:#ffffff;"><div class="grid2" style="max-width:1080px; margin:0 auto; display:grid; grid-template-columns:1fr 1fr; gap:60px; align-items:center;"><div style="border-radius:22px; overflow:hidden; height:460px;"><img src="https://sustable.eu/wp-content/uploads/2026/01/DSC02954-min-1365x2048.jpg" alt="Sustable Solartisch auf einer Terrasse" loading="lazy" style="width:100%; height:100%; object-fit:cover; display:block;"></div><div><div style="color:#86868b; font-weight:600; font-size:13px; letter-spacing:0.12em; text-transform:uppercase; margin-bottom:14px;">Unsere Geschichte</div><h2 style="margin:0 0 20px; font-size:34px; font-weight:700; letter-spacing:-0.02em; color:#1d1d1f;">Aus einer einfachen Frage entstand eine neue Möbelkategorie.</h2><p style="margin:0 0 16px; font-size:15.5px; line-height:1.75; color:#6e6e73;">Warum verschenken wir wertvolle Sonnenfläche auf Terrasse und Balkon, während Gartenmöbel dort ohnehin den ganzen Tag in der Sonne stehen? Aus dieser Idee wurde der Sustable Solartisch.</p><p style="margin:0; font-size:15.5px; line-height:1.75; color:#6e6e73;">Als Teil von e-con verbinden wir technisches Know-how aus der Energiebranche mit hochwertigem Möbeldesign – und machen saubere Energie für jeden zugänglich, ganz ohne eigene Dachfläche.</p></div></div></section>'
  + '<section style="padding:70px 32px; background:#f5f5f7;"><div class="grid3" style="max-width:1080px; margin:0 auto; display:grid; grid-template-columns:1fr 1fr 1fr; gap:24px; text-align:center;"><div><div style="font-size:44px; font-weight:800; letter-spacing:-0.02em; color:#1d1d1f;">2024</div><div style="font-size:14.5px; color:#6e6e73; margin-top:6px;">Gegründet, powered by e-con</div></div><div><div style="font-size:44px; font-weight:800; letter-spacing:-0.02em; color:#1d1d1f;"><span data-countup="10">10</span> Jahre</div><div style="font-size:14.5px; color:#6e6e73; margin-top:6px;">Garantie auf jeden Solartisch</div></div><div><div style="font-size:44px; font-weight:800; letter-spacing:-0.02em; color:#1d1d1f;"><span data-countup="100">100</span> %</div><div style="font-size:14.5px; color:#6e6e73; margin-top:6px;">Made &amp; Support in Germany</div></div></div></section>'
  + '<section style="padding:110px 32px; background:#ffffff;"><div style="max-width:1080px; margin:0 auto;"><h2 style="margin:0 0 44px; font-size:34px; font-weight:700; letter-spacing:-0.02em; color:#1d1d1f; text-align:center;">Wofür wir stehen.</h2><div class="grid3" style="display:grid; grid-template-columns:1fr 1fr 1fr; gap:20px;">'
  + benefit('<path d="M11 20A7 7 0 0 1 9.8 6.1C15.5 5 17 4.48 19 2c1 2 2 4.18 2 8 0 5.5-4.78 10-10 10Z"></path><path d="M2 21c0-3 1.85-5.36 5.08-6C9.5 14.52 12 13 13 12"></path>','Nachhaltigkeit','Saubere Energie und langlebige Materialien statt Wegwerfprodukte – ein Beitrag zu einer besseren Zukunft.')
  + benefit('<path d="M12 19l7-7 3 3-7 7-3-3z"></path><path d="M18 13l-1.5-7.5L2 2l3.5 14.5L13 18l5-5z"></path><path d="M2 2l7.586 7.586"></path><circle cx="11" cy="11" r="2"></circle>','Design','Technik, die man nicht verstecken muss. Unsere Solartische sind ein Statement für modernes, zeitloses Design.')
  + benefit('<path d="M20 10c0 6-8 12-8 12s-8-6-8-12a8 8 0 0 1 16 0Z"></path><circle cx="12" cy="10" r="3"></circle>','Regionalität','Kurze Wege, faire Arbeitsbedingungen und Fertigung in Deutschland – Qualität, der du vertrauen kannst.')
  + '</div></div></section>'
  + '<section style="padding:0 32px 110px; background:#ffffff;"><div style="max-width:1080px; margin:0 auto; background:#0a0a0c; border-radius:26px; padding:64px 50px; text-align:center;"><h2 style="margin:0 0 16px; font-size:32px; font-weight:700; letter-spacing:-0.02em; color:#ffffff;">Lerne Sustable kennen.</h2><p style="margin:0 auto 32px; max-width:480px; font-size:15.5px; line-height:1.6; color:#86868b;">Ob privat auf der Terrasse oder als Händler im Sortiment – wir freuen uns auf dich.</p><div style="display:flex; gap:14px; justify-content:center; flex-wrap:wrap;"><a href="/shop/" style="cursor:pointer; display:inline-flex; align-items:center; gap:9px; background:#ffffff; color:#111113; border-radius:980px; padding:14px 30px; font-weight:600; font-size:15px;">Zum Shop</a><a href="/business/" style="cursor:pointer; display:inline-flex; align-items:center; background:transparent; color:#ffffff; border:1.5px solid rgba(255,255,255,0.4); border-radius:980px; padding:13px 28px; font-weight:600; font-size:15px;">Für Händler</a></div></div></section>'
  + '</div>';
}

/* ---------------- MEHR ERFAHREN ---------------- */
function mehrRow(img, title, text, imgLeft){
  var imgBlock = '<div style="border-radius:22px; overflow:hidden;'+(img.bg?' background:#f5f5f7;':'')+'"><img src="'+img.src+'" alt="'+esc(title)+'" loading="lazy" style="width:100%; height:340px; object-fit:'+(img.fit||'cover')+'; display:block;"></div>';
  var textBlock = '<div><h2 style="margin:0 0 16px; font-size:27px; font-weight:700; letter-spacing:-0.01em; color:#1d1d1f;">'+title+'</h2><p style="margin:0; font-size:15.5px; line-height:1.75; color:#6e6e73;">'+text+'</p></div>';
  return '<div class="grid2" style="display:grid; grid-template-columns:1fr 1fr; gap:56px; align-items:center;">'+(imgLeft?imgBlock+textBlock:textBlock+imgBlock)+'</div>';
}
function pageMehr(){
  return '<div style="background:#ffffff;">'
  + '<section style="background:#f5f5f7; padding:90px 32px;"><div class="grid2" style="max-width:1100px; margin:0 auto; display:grid; grid-template-columns:1.2fr 1fr; gap:60px; align-items:center;"><div><div style="color:#86868b; font-weight:600; font-size:13px; letter-spacing:0.12em; text-transform:uppercase; margin-bottom:14px;">Mehr erfahren</div><h1 style="margin:0 0 22px; font-size:46px; line-height:1.15; font-weight:700; letter-spacing:-0.02em; color:#1d1d1f;">Mehr Informationen zu unseren Solartischen.</h1><p style="margin:0 0 32px; font-size:17px; line-height:1.7; color:#6e6e73;">Unsere Solartische vereinen modernes Design mit nachhaltiger Energiegewinnung. Sie bieten die volle Funktionalität eines klassischen Gartentisches – mit dem zusätzlichen Vorteil, Sonnenenergie in Strom umzuwandeln.</p><a href="/shop/" style="cursor:pointer; display:inline-flex; align-items:center; gap:9px; background:#111113; color:#ffffff; border-radius:980px; padding:13px 28px; font-weight:600; font-size:15px;">Jetzt entdecken '+arrowW+'</a></div><div style="border-radius:22px; overflow:hidden; max-height:440px;"><img src="https://sustable.eu/wp-content/uploads/2026/01/DSC02954-min-1365x2048.jpg" alt="Sustable Solartisch im Detail" loading="lazy" style="width:100%; height:440px; object-fit:cover; display:block;"></div></div></section>'
  + '<section class="mehr-flex" style="padding:90px 32px; max-width:1100px; margin:0 auto; display:flex; flex-direction:column; gap:90px;">'
  + mehrRow({src:'https://sustable.eu/wp-content/uploads/2026/01/DSC02941-min-2048x1365.jpg'}, 'Wärmeentwicklung und Langlebigkeit.', 'Auch unsere Solarplatte erwärmt sich durch direkte Sonne. Durch die Stromerzeugung heizt sie sich jedoch weniger auf als Kunststoff- oder Metallplatten. Die Solartische sind für den dauerhaften Außeneinsatz gemacht und halten Regen, Schnee und Hagel stand – ganzjährig und ohne Funktionsverlust.', true)
  + mehrRow({src:'https://sustable.eu/wp-content/uploads/2025/11/ChatGPT-Image-26.-Juni-2025-16_46_53-e1762325531499.png'}, 'Pflegeleicht und unkompliziert.', 'Die Glasoberfläche kann einfach mit einem feuchten Tuch und mildem Reinigungsmittel gereinigt werden. Kratzer werden durch das gehärtete Glas vermieden.', false)
  + mehrRow({src:'https://sustable.eu/wp-content/uploads/2025/10/One_7.avif', fit:'contain', bg:true}, 'Technische Eigenschaften und Stabilität.', 'Die Solarplatten bestehen aus leistungsstarken Modulen mit einem stabilen Aluminiumrahmen. Die Solarzellen sind dauerhaft mit der Glasplatte verbunden, sodass die Konstruktion widerstandsfähig bleibt. Selbst hohe Schneelasten oder starke Stöße können der Oberfläche kaum etwas anhaben.', true)
  + mehrRow({src:'https://sustable.eu/wp-content/uploads/2025/10/One_6.avif', fit:'contain', bg:true}, 'Effizienz und Standortwahl.', 'Die Stromausbeute hängt – wie bei allen Solarmodulen – von der Sonneneinstrahlung ab. Es empfiehlt sich eine Platzierung an einem möglichst sonnigen Ort. Bereits kleine Schatten, etwa von einem Sonnenschirm-Stiel, können den Wirkungsgrad beeinträchtigen.', false)
  + mehrRow({src:'https://sustable.eu/wp-content/uploads/2025/11/ChatGPT-Image-26.-Juni-2025-16_31_20-e1762326075709.png'}, 'Einspeisen über eine Steckdose.', 'Der erzeugte Solarstrom wird direkt über eine haushaltsübliche Steckdose ins Hausnetz eingespeist. Der Wechselrichter verfügt über einen automatischen Netz- und Anlagenschutz, der die Einspeisung sofort unterbricht, sobald der Stecker gezogen wird.', true)
  + mehrRow({src:'https://sustable.eu/wp-content/uploads/2025/11/Bildschirmfoto-2025-06-26-um-17.01.18-e1762326152515.png'}, 'Kein Einfluss auf den Nutzungskomfort.', 'Die stabile Bauweise ermöglicht eine uneingeschränkte Nutzung im Alltag. Geschirr, Gläser oder andere Gegenstände können bedenkenlos direkt auf der Glasplatte abgestellt werden.', false)
  + '</section>'
  + '<section style="padding:0 32px 110px;"><div style="max-width:1100px; margin:0 auto; background:#f5f5f7; border-radius:22px; padding:50px; display:flex; align-items:center; justify-content:space-between; gap:30px; flex-wrap:wrap;"><div><h2 style="margin:0 0 8px; font-size:25px; font-weight:700; letter-spacing:-0.01em;">Bereit für dein eigenes Tischkraftwerk?</h2><p style="margin:0; font-size:14.5px; color:#6e6e73;">Sustable ONE+ Edelstahl · 1.750 € · 10 Jahre Garantie</p></div><div style="display:flex; gap:14px; flex-wrap:wrap;"><button type="button" data-add="one-plus" style="cursor:pointer; display:inline-flex; align-items:center; background:#111113; color:#ffffff; border:0; border-radius:980px; padding:13px 28px; font-weight:600; font-size:15px;">In den Warenkorb</button><a href="'+productPath(prod('one-plus'))+'" style="cursor:pointer; display:inline-flex; align-items:center; background:transparent; color:#1d1d1f; border:1.5px solid #c7c7cc; border-radius:980px; padding:12px 26px; font-weight:600; font-size:15px;">Zum Produkt</a></div></div></section>'
  + '</div>';
}

/* ---------------- BUSINESS ---------------- */
function pageBusiness(){
  var CAL='https://calendar.app.google/j1BujJkMVCzWWSyg6';
  function adv(svg,title,text){ return '<div style="background:#ffffff; border-radius:20px; padding:34px;"><svg width="24" height="24" viewBox="0 0 24 24" fill="none" stroke="#1d1d1f" stroke-width="1.8" stroke-linecap="round" stroke-linejoin="round" style="margin-bottom:16px;" aria-hidden="true">'+svg+'</svg><h3 style="margin:0 0 8px; font-size:18px; font-weight:700;">'+title+'</h3><p style="margin:0; font-size:14.5px; line-height:1.65; color:#6e6e73;">'+text+'</p></div>'; }
  function contact(img,name,mail,tel,telHref){ return '<div style="background:#f5f5f7; border-radius:22px; padding:38px; text-align:center;"><img src="'+img+'" alt="'+esc(name)+'" loading="lazy" width="110" height="110" style="width:110px; height:110px; border-radius:50%; object-fit:cover; margin:0 auto 18px; display:block;"><div style="font-weight:700; font-size:18px; margin-bottom:4px;">'+name+'</div><div style="font-size:13.5px; color:#86868b; margin-bottom:16px;">Vertrieb &amp; Partnermanagement</div><div style="font-size:14.5px; line-height:1.9; color:#424245; margin-bottom:22px;"><a href="mailto:'+mail+'" style="color:#1d1d1f; font-weight:600; text-decoration:underline;">'+mail+'</a><br><a href="'+telHref+'" style="color:#1d1d1f; font-weight:600;">'+tel+'</a></div><a href="'+CAL+'" target="_blank" rel="noopener" style="display:inline-flex; align-items:center; background:#111113; color:#ffffff; border-radius:980px; padding:11px 24px; font-weight:600; font-size:14px;">Termin buchen</a></div>'; }
  return '<div>'
  + '<section style="background:#0a0a0c; padding:110px 32px;"><div style="max-width:1080px; margin:0 auto; text-align:center;"><div style="color:#86868b; font-weight:600; font-size:13px; letter-spacing:0.12em; text-transform:uppercase; margin-bottom:16px;">Sustable Business</div><h1 style="margin:0 0 24px; font-size:52px; line-height:1.12; font-weight:700; letter-spacing:-0.02em; color:#ffffff;">Solartische für Unternehmen &amp; Gastronomie.</h1><div style="display:flex; gap:12px; justify-content:center; flex-wrap:wrap; margin-bottom:42px;"><span style="background:rgba(255,255,255,0.08); border:1px solid rgba(255,255,255,0.16); color:#ffffff; font-size:13px; font-weight:600; padding:8px 18px; border-radius:980px;">Made in Germany</span><span style="background:rgba(255,255,255,0.08); border:1px solid rgba(255,255,255,0.16); color:#ffffff; font-size:13px; font-weight:600; padding:8px 18px; border-radius:980px;">10 Jahre Garantie</span><span style="background:rgba(255,255,255,0.08); border:1px solid rgba(255,255,255,0.16); color:#ffffff; font-size:13px; font-weight:600; padding:8px 18px; border-radius:980px;">100 % technischer Kundensupport</span></div><div style="display:flex; gap:14px; justify-content:center; flex-wrap:wrap;"><a href="'+CAL+'" target="_blank" rel="noopener" style="display:inline-flex; align-items:center; gap:9px; background:#ffffff; color:#111113; border-radius:980px; padding:15px 32px; font-weight:600; font-size:16px;">Jetzt Termin buchen '+arrowD+'</a><a href="https://sustable.eu/wp-content/uploads/2026/03/Broschuere.pdf" target="_blank" rel="noopener" style="display:inline-flex; align-items:center; background:transparent; color:#ffffff; border:1.5px solid rgba(255,255,255,0.4); border-radius:980px; padding:14px 30px; font-weight:600; font-size:16px;">Broschüre herunterladen</a></div></div></section>'
  + '<section style="padding:110px 32px; background:#ffffff;"><div class="grid2" style="max-width:1080px; margin:0 auto; display:grid; grid-template-columns:1fr 1fr; gap:60px; align-items:center;"><div><div style="color:#86868b; font-weight:600; font-size:13px; letter-spacing:0.12em; text-transform:uppercase; margin-bottom:14px;">Design trifft Energie</div><h2 style="margin:0 0 20px; font-size:36px; font-weight:700; letter-spacing:-0.02em; color:#1d1d1f;">Die neue Produktkategorie für den modernen Outdoor-Markt.</h2><p style="margin:0 0 16px; font-size:15.5px; line-height:1.75; color:#6e6e73;">Wir verbinden zeitlose Ästhetik mit nachhaltiger Innovation. Unsere Solartische sind mehr als nur Möbel – sie sind ein Statement für einen nachhaltigen Lifestyle, verpackt in hochwertigem Design.</p><p style="margin:0 0 30px; font-size:15.5px; line-height:1.75; color:#6e6e73;">Sie sind Category Manager oder Einkäufer und suchen nach einem echten USP für Ihr Sortiment? Entdecken Sie mit Sustable eine völlig neue Möbelkategorie, die Design und Funktion perfekt vereint.</p><a href="'+CAL+'" target="_blank" rel="noopener" style="display:inline-flex; align-items:center; gap:9px; background:#111113; color:#ffffff; border-radius:980px; padding:13px 28px; font-weight:600; font-size:15px;">Unverbindliches Angebot anfragen</a></div><div style="background:#f5f5f7; border-radius:22px; padding:40px; display:flex; align-items:center; justify-content:center;"><img src="https://sustable.eu/wp-content/uploads/2025/10/One_1.avif" alt="Sustable ONE+ für Geschäftskunden" loading="lazy" style="max-width:100%; height:auto; display:block;"></div></div></section>'
  + '<section style="padding:100px 32px; background:#f5f5f7;"><div style="max-width:1080px; margin:0 auto;"><h2 style="margin:0 0 44px; font-size:34px; font-weight:700; letter-spacing:-0.02em; color:#1d1d1f; text-align:center;">Ihre Vorteile als Geschäftspartner.</h2><div class="grid3" style="display:grid; grid-template-columns:1fr 1fr 1fr; gap:20px;">'
  + adv('<path d="M3 3v16a2 2 0 0 0 2 2h16"></path><path d="M7 14l4-4 3 3 5-6"></path>','Exklusive Konditionen','Attraktive Handelsmargen und faire Partnerkonditionen für Ihr Sortiment.')
  + adv('<path d="M16 21v-2a4 4 0 0 0-4-4H6a4 4 0 0 0-4 4v2"></path><circle cx="9" cy="7" r="4"></circle><path d="M22 21v-2a4 4 0 0 0-3-3.87"></path><path d="M16 3.13a4 4 0 0 1 0 7.75"></path>','Persönliche Betreuung','Feste Ansprechpartner, Schulung Ihres Teams und Unterstützung am POS.')
  + adv('<path d="M20 13c0 5-3.5 7.5-7.66 8.95a1 1 0 0 1-.67-.01C7.5 20.5 4 18 4 13V6a1 1 0 0 1 1-1c2 0 4.5-1.2 6.24-2.72a1 1 0 0 1 1.52 0C14.51 3.81 17 5 19 5a1 1 0 0 1 1 1z"></path><path d="m9 12 2 2 4-4"></path>','Erstklassige Qualität','Made in Germany, 10 Jahre Garantie und 100 % technischer Kundensupport.')
  + '</div></div></section>'
  + '<section style="padding:110px 32px; background:#ffffff;"><div style="max-width:880px; margin:0 auto;"><h2 style="margin:0 0 14px; font-size:34px; font-weight:700; letter-spacing:-0.02em; color:#1d1d1f; text-align:center;">Ihre Ansprechpartner.</h2><p style="margin:0 auto 48px; max-width:520px; text-align:center; font-size:15.5px; color:#6e6e73; line-height:1.6;">Buchen Sie direkt einen Termin – wir melden uns innerhalb von 24 Stunden.</p><div class="grid2" style="display:grid; grid-template-columns:1fr 1fr; gap:24px;">'
  + contact('https://sustable.eu/wp-content/uploads/2026/03/louis-mueller-q.jpg','Louis Müller','louis.mueller@sustable.eu','+49 1514 1872588','tel:+4915141872588')
  + contact('https://sustable.eu/wp-content/uploads/2026/03/nils-schreitmueller-q.jpg','Nils Schreitmüller','nils.schreitmueller@sustable.eu','+49 159 01129733','tel:+4915901129733')
  + '</div></div></section>'
  + '<section style="padding:90px 32px; background:#0a0a0c;"><div style="max-width:880px; margin:0 auto; text-align:center;"><h2 style="margin:0 0 28px; font-size:34px; font-weight:700; letter-spacing:-0.02em; color:#ffffff;">Setzen wir gemeinsam neue Maßstäbe im Möbelhandel.</h2><a href="'+CAL+'" target="_blank" rel="noopener" style="display:inline-flex; align-items:center; gap:9px; background:#ffffff; color:#111113; border-radius:980px; padding:15px 32px; font-weight:600; font-size:16px;">Jetzt Kontakt aufnehmen '+arrowD+'</a></div></section>'
  + '</div>';
}

/* ---------------- HÄNDLERSUCHE ---------------- */
function pageHaendler(){
  var cards = DEALERS.map(function(d){
    return '<div style="background:#ffffff; border-radius:20px; padding:28px;"><div style="display:flex; justify-content:space-between; align-items:baseline; gap:12px; margin-bottom:4px;"><h2 style="margin:0; font-size:18px; font-weight:700; color:#1d1d1f;">'+d.name+'</h2><span class="dealer-dist" data-dealer-dist="'+d.id+'" style="font-size:13.5px; font-weight:700; color:#e8821d; white-space:nowrap;"></span></div>'
    + '<div style="font-size:13.5px; color:#86868b; margin-bottom:14px;">'+d.untertitel+'</div>'
    + '<address style="font-style:normal; font-size:14.5px; line-height:1.7; color:#424245; margin-bottom:8px;">'+d.strasse+'<br>'+d.ort+'</address>'
    + '<div style="font-size:14.5px; line-height:1.8; color:#424245; margin-bottom:6px;">Tel. <a href="'+d.telHref+'" style="color:#1d1d1f; font-weight:600;">'+d.tel+'</a><br><a href="'+d.mailHref+'" style="color:#1d1d1f; font-weight:600; text-decoration:underline;">'+d.mail+'</a></div>'
    + (d.zeiten1?'<div style="font-size:13.5px; line-height:1.7; color:#424245; background:#f5f5f7; border-radius:12px; padding:10px 14px; margin:10px 0 4px;"><span style="font-weight:600;">Öffnungszeiten</span><br>'+d.zeiten1+'<br>'+d.zeiten2+'</div>':'')
    + '<div style="display:flex; gap:10px; margin-top:16px; flex-wrap:wrap;"><button type="button" data-dealer-show="'+d.id+'" style="cursor:pointer; display:inline-flex; align-items:center; background:#111113; color:#ffffff; border:0; border-radius:980px; padding:9px 18px; font-weight:600; font-size:13.5px;">Auf Karte zeigen</button><a href="'+d.routeHref+'" target="_blank" rel="noopener" style="display:inline-flex; align-items:center; background:transparent; color:#1d1d1f; border:1.5px solid #c7c7cc; border-radius:980px; padding:8px 17px; font-weight:600; font-size:13.5px;">Route planen</a></div></div>';
  }).join('');
  return '<div style="background:#f5f5f7; padding:80px 32px 110px; min-height:70vh;"><div style="max-width:1180px; margin:0 auto;"><div style="text-align:center; margin-bottom:44px;"><div style="color:#86868b; font-weight:600; font-size:13px; letter-spacing:0.12em; text-transform:uppercase; margin-bottom:14px;">Händlersuche</div><h1 style="margin:0 0 16px; font-size:46px; font-weight:700; letter-spacing:-0.02em; color:#1d1d1f;">Sustable Händler finden.</h1><p style="margin:0; font-size:17px; color:#6e6e73;">Gib deine Stadt oder Postleitzahl ein und finde den nächsten Sustable-Fachhändler.</p></div>'
  + '<div style="display:flex; gap:12px; max-width:600px; margin:0 auto 18px;"><input type="text" id="search-input" placeholder="Stadt oder Postleitzahl eingeben" aria-label="Stadt oder Postleitzahl" style="flex:1; padding:14px 22px; font-size:15.5px; border:1px solid #d2d2d7; border-radius:980px; background:#ffffff; color:#1d1d1f; outline:none;"><button type="button" id="search-submit" style="cursor:pointer; display:inline-flex; align-items:center; background:#111113; color:#ffffff; border:0; border-radius:980px; padding:14px 30px; font-weight:600; font-size:15px;">Suchen</button></div>'
  + '<div id="search-info" style="text-align:center; margin-bottom:24px; font-size:14.5px; font-weight:600; color:#1d1d1f; min-height:18px;"></div>'
  + '<div class="grid2" style="display:grid; grid-template-columns:1.4fr 1fr; gap:22px; align-items:start; margin-top:28px;"><div id="map" style="height:540px; border-radius:22px; overflow:hidden; background:#e8e8ed;"></div><div style="display:flex; flex-direction:column; gap:16px;">'+cards+'<div style="font-size:13px; color:#86868b; line-height:1.6; padding:0 6px;">Du bist Händler und möchtest Sustable in dein Sortiment aufnehmen? <a href="/business/" style="color:#1d1d1f; font-weight:600; text-decoration:underline;">Werde Partner →</a></div></div></div></div></div>';
}

/* ---------------- SOLARTISCH (Keyword-Landingpage) ---------------- */
function pageSolartisch(){
  return '<div style="background:#ffffff;">'
  + '<section style="background:#f5f5f7; padding:90px 32px;"><div style="max-width:860px; margin:0 auto; text-align:center;"><div style="color:#86868b; font-weight:600; font-size:13px; letter-spacing:0.12em; text-transform:uppercase; margin-bottom:14px;">Ratgeber</div><h1 style="margin:0 0 22px; font-size:48px; line-height:1.14; font-weight:700; letter-spacing:-0.02em; color:#1d1d1f;">Was ist ein Solartisch?</h1><p style="margin:0 auto; max-width:600px; font-size:18px; line-height:1.65; color:#424245;">Ein Solartisch ist ein vollwertiger Gartentisch mit integriertem Solarmodul. Er erzeugt sauberen Strom direkt auf deiner Terrasse – und speist ihn per Steckdose ins Hausnetz ein. Hier erfährst du, wie er funktioniert, was er bringt und was er kostet.</p></div></section>'
  + '<section style="padding:80px 32px; max-width:820px; margin:0 auto;"><div style="display:flex; flex-direction:column; gap:40px;">'
  + '<div><h2 style="margin:0 0 12px; font-size:28px; font-weight:700; letter-spacing:-0.01em; color:#1d1d1f;">Wie funktioniert ein Solartisch?</h2><p style="margin:0; font-size:16.5px; line-height:1.8; color:#2c2c2e;">In der Tischplatte sitzt ein leistungsstarkes Photovoltaik-Modul. Es wandelt Sonnenlicht in Gleichstrom um, den ein integrierter 500 W-Mikro-Wechselrichter in haushaltsüblichen Wechselstrom umwandelt. Über eine normale Außensteckdose fließt dieser Strom direkt in dein Hausnetz – ganz ohne Installation, nach dem Plug-&-Play-Prinzip eines Balkonkraftwerks.</p></div>'
  + '<div><h2 style="margin:0 0 12px; font-size:28px; font-weight:700; letter-spacing:-0.01em; color:#1d1d1f;">Wie viel Strom erzeugt ein Solartisch?</h2><p style="margin:0; font-size:16.5px; line-height:1.8; color:#2c2c2e;">Mit einem 465 Wp-Modul erzeugt der Sustable ONE+ je nach Standort und Sonneneinstrahlung rund 450–510 kWh pro Jahr. Das entspricht ungefähr dem Jahresverbrauch eines effizienten Kühlschranks. Wie viel du damit konkret sparst, kannst du im <a href="/#rechner" style="color:#1d1d1f; font-weight:600; text-decoration:underline;">Ersparnis-Rechner</a> ausrechnen.</p></div>'
  + '<div><h2 style="margin:0 0 12px; font-size:28px; font-weight:700; letter-spacing:-0.01em; color:#1d1d1f;">Was kostet ein Solartisch?</h2><p style="margin:0; font-size:16.5px; line-height:1.8; color:#2c2c2e;">Die Sustable Solartische starten bei 1.190 € (Sustable mini) und reichen bis 1.750 € für das Edelstahl-Flaggschiff Sustable ONE+. Als Tischkraftwerk mit integrierter Photovoltaik unter 30 kWp gilt für den privaten Gebrauch der Umsatzsteuersatz von 0 % nach § 12 Abs. 3 UStG.</p></div>'
  + '<div><h2 style="margin:0 0 12px; font-size:28px; font-weight:700; letter-spacing:-0.01em; color:#1d1d1f;">Muss ein Solartisch angemeldet werden?</h2><p style="margin:0; font-size:16.5px; line-height:1.8; color:#2c2c2e;">Da die Leistung unter der 800 W-Grenze für Balkonkraftwerke liegt, ist keine Genehmigung nötig. Seit April 2024 genügt eine einfache Anmeldung im Marktstammdatenregister. Weitere Antworten findest du in unseren <a href="/faq/" style="color:#1d1d1f; font-weight:600; text-decoration:underline;">häufigen Fragen</a>.</p></div>'
  + '</div></section>'
  + '<section style="padding:0 32px 110px;"><div style="max-width:820px; margin:0 auto; background:#0a0a0c; border-radius:26px; padding:56px 44px; text-align:center;"><h2 style="margin:0 0 14px; font-size:30px; font-weight:700; letter-spacing:-0.02em; color:#ffffff;">Den Sustable Solartisch entdecken.</h2><p style="margin:0 auto 30px; max-width:480px; font-size:15.5px; line-height:1.6; color:#86868b;">Premium-Design, Made im Allgäu, 10 Jahre Garantie.</p><a href="'+productPath(prod('one-plus'))+'" style="display:inline-flex; align-items:center; gap:9px; background:#ffffff; color:#111113; border-radius:980px; padding:14px 30px; font-weight:600; font-size:15px;">Zum Sustable ONE+ '+arrowD+'</a></div></section>'
  + '</div>';
}

